select * from hrm_holiday_deduction AS a LEFT JOIN
    hrm_remaining_vacation AS b ON a.holiday_id = b.holiday_id WHERE 1=1

    AND b.employee_id = #{data.employeeId}


    AND a.type = #{data.type}


    AND a.year = #{data.year}


    AND a.month = #{data.month}

SELECT b.deduction_time as deductionTime,type FROM (
SELECT * FROM hrm_remaining_vacation WHERE 1=1

    AND employee_id = #{data.employeeId}

) as a
LEFT JOIN hrm_holiday_deduction AS b ON a.holiday_id = b.holiday_id
WHERE 1=1

    AND b.year = #{data.year}
    AND b.month = #{data.month}



    AND b.type = #{data.type}
